            conn
            |> put_status(:bad_gateway)
            |> json(%{error: "upstream_request_failed", reason: inspect(reason)})
        end

      {:error, reason} ->
        conn
        |> put_status(:bad_request)
        |> json(%{error: "invalid_url", reason: reason})
    end
  end

